<?php if($mode==='index'): ?><section class="card"><div class="actions"><form><input name="search" placeholder="Search" value="<?= e($_GET['search'] ?? '') ?>"><button>Search</button></form><a class="button primary" href="/<?= e($module) ?>/create">Create</a></div><table><tr><th>ID</th><?php foreach($fields as $name=>$meta): ?><th><?= e($meta['label'] ?? $name) ?></th><?php endforeach; ?><th>Actions</th></tr><?php foreach($rows as $row): ?><tr><td><?= e($row['id']) ?></td><?php foreach($fields as $name=>$meta): ?><td><?= e($row[$name] ?? '') ?></td><?php endforeach; ?><td><a href="/<?= e($module) ?>/<?= e($row['id']) ?>/edit">Edit</a><form class="inline" method="post" action="/<?= e($module) ?>/<?= e($row['id']) ?>/delete"><?= csrf_field() ?><button>Delete</button></form></td></tr><?php endforeach; ?></table></section><?php else: ?><section class="card"><form method="post" action="/<?= e($module) ?><?= !empty($row['id'])?'/'.e($row['id']):'' ?>"><?= csrf_field() ?><div class="form-grid"><?php foreach($fields as $name=>$meta): ?><label><?= e($meta['label'] ?? $name) ?><?php if(($meta['type']??'text')==='textarea'): ?><textarea name="<?= e($name) ?>"><?= e($row[$name] ?? '') ?></textarea><?php elseif(($meta['type']??'text')==='select'): ?><select name="<?= e($name) ?>"><?php foreach(($meta['options']??[]) as $k=>$v): ?><option value="<?= e($k) ?>" <?= (string)($row[$name] ?? $meta['default'] ?? '')===(string)$k?'selected':'' ?>><?= e($v) ?></option><?php endforeach; ?></select><?php else: ?><input type="<?= e($meta['type'] ?? 'text') ?>" step="0.01" name="<?= e($name) ?>" value="<?= e($row[$name] ?? $meta['default'] ?? '') ?>"><?php endif; ?></label><?php endforeach; ?></div><button class="primary">Save</button></form></section><?php endif; ?>
